const queries = [
  // === RFPZONE.COM — private sector filter ===
  { q: 'site:rfpzone.com "AI" OR "machine learning" OR "automation" OR "software development"', platform: 'rfpzone' },
  { q: 'site:rfpzone.com "technology" OR "data" OR "software" "private sector" OR "corporate"', platform: 'rfpzone' },
  { q: 'site:rfpzone.com "custom software" OR "AI development" OR "data pipeline" OR "enterprise software"', platform: 'rfpzone' },

  // === INSTANTMARKETS.COM — private sector filter ===
  { q: 'site:instantmarkets.com "AI" OR "machine learning" OR "automation" OR "software"', platform: 'instantmarkets' },
  { q: 'site:instantmarkets.com "technology" OR "data" OR "software development" OR "enterprise"', platform: 'instantmarkets' },
  { q: 'site:instantmarkets.com "custom software" OR "AI" OR "SaaS" OR "platform development"', platform: 'instantmarkets' },

  // === FINDRFP.COM — corporate section ===
  { q: 'site:findrfp.com "AI" OR "machine learning" OR "automation" OR "software development"', platform: 'findrfp' },
  { q: 'site:findrfp.com "technology" OR "data analytics" OR "software" corporate OR private', platform: 'findrfp' },
  { q: 'site:findrfp.com "SaaS" OR "enterprise software" OR "data pipeline" OR "computer vision"', platform: 'findrfp' },

  // === RFPDB.COM — RFP Database ===
  { q: 'site:rfpdb.com "AI" OR "machine learning" OR "automation" OR "software development"', platform: 'rfpdb' },
  { q: 'site:rfpdb.com "technology" OR "data" OR "analytics" "private" OR "corporate"', platform: 'rfpdb' },
  { q: 'site:rfpdb.com "custom software" OR "AI development" OR "SaaS" OR "enterprise software"', platform: 'rfpdb' }
];
return queries.map(q => ({ json: q }));

const skipKeywords = [
  'agency directory', 'top agencies', 'best agencies', 'find agencies',
  'compare agencies', 'agency profile', 'government rfp', 'federal contract',
  'state government', 'county government', 'municipal', 'school district',
  'for hire', 'logo design', 'seo services', 'social media manager',
  'content writer', 'virtual assistant', 'data entry', 'graphic design'
];

const platformMap = {
  'rfpzone.com': 'rfpzone',
  'instantmarkets.com': 'instantmarkets',
  'findrfp.com': 'findrfp',
  'rfpdb.com': 'rfpdb'
};

const budgetPatterns = [
  /budget[:\s]+([\$€£][\d,k.]+[\s\w-]*)/i,
  /([\$€£][\d,]+(?:,\d{3})*(?:k)?(?:\s[-–]\s*[\$€£]?[\d,]+(?:k)?)?(?:\s*(?:USD|EUR|GBP))?)/i,
  /(\d+[kK][\s-–]+(\d+[kK]))/,
  /([\$€£]\d+(?:\.\d+)?[kK])/i
];

const results = [];
const seenInRun = new Set();

for (const item of $input.all()) {
  const data = item.json;
  if (!data || data.error) continue;

  const searchQ = data.search_parameters?.q || '';
  const organicResults = data.organic_results || [];

  // Detect platform from query
  let platform = 'unknown';
  for (const [domain, pname] of Object.entries(platformMap)) {
    if (searchQ.includes(domain)) { platform = pname; break; }
  }

  for (const r of organicResults) {
    const link = r.link || '';
    if (!link) continue;

    // Detect platform from actual URL if still unknown
    let actualPlatform = platform;
    if (actualPlatform === 'unknown') {
      for (const [domain, pname] of Object.entries(platformMap)) {
        if (link.includes(domain)) { actualPlatform = pname; break; }
      }
    }
    if (actualPlatform === 'unknown') continue;

    const id = actualPlatform + '_' + link.replace(/[^a-z0-9]/gi, '').slice(-60);
    if (seenInRun.has(id)) continue;
    seenInRun.add(id);

    const title   = String(r.title   || '').substring(0, 500);
    const snippet = String(r.snippet || '').replace(/<[^>]*>/g, '').substring(0, 3000);
    if (!title) continue;

    const fullText = (title + ' ' + snippet).toLowerCase();
    if (skipKeywords.some(kw => fullText.includes(kw))) continue;

    // Extract budget from snippet
    let budget_text = '';
    for (const pat of budgetPatterns) {
      const m = (snippet + ' ' + title).match(pat);
      if (m) { budget_text = (m[1] || m[0]).trim().substring(0, 80); break; }
    }

    results.push({ json: {
      title,
      description: snippet,
      source: actualPlatform,
      source_url: link,
      source_id: id,
      posted_at: (() => { try { const d = r.date ? new Date(r.date) : null; return (d && !isNaN(d)) ? d.toISOString() : new Date().toISOString(); } catch(e) { return new Date().toISOString(); } })(),
      author: '',
      subreddit: actualPlatform,
      upvotes: 0,
      num_comments: 0,
      flair_text: 'Private RFP',
      budget_text,
      platform: actualPlatform
    }});
  }
}

if (results.length === 0) return [{ json: { _empty: true, platform: 'private-rfp' } }];
// Cap at 30 leads per run to avoid Gemini rate-limit timeouts
return results.slice(0, 30);

const post = $input.item.json;
if (post._empty || post._noData) return { json: post };

const apiKey = $env.GOOGLE_AI_API_KEY;

const SYSTEM_PROMPT = `You are a senior business development analyst for ScaleBuild AI (CEO: Ujjwal Roy, ex-Intel/IBM/Micron), a custom AI/ML software development company.

ScaleBuild BUILDS: AI/ML models, computer vision, enterprise automation, custom software, data pipelines.

These leads are PRIVATE SECTOR RFPs (Requests for Proposals) sourced from RFP aggregator platforms (RFPZone, InstantMarkets, FindRFP, RFPdb). These are formal procurement requests from private companies actively seeking software/technology vendors.

IDEAL LEAD: A private company RFP explicitly seeking AI, ML, automation, custom software, data pipeline, or enterprise technology services.

HARD EXCLUSIONS — Score overall_score 0.0 immediately, do not process:
- Lead is from India or an Indian company (location: India, .in domain, Indian city/company name context) → 0.0
- Lead is requesting to build a SaaS subscription product (we do NOT build SaaS products) → 0.0  
- Budget is clearly under $10,000 OR budget_score would be below 0.3 → 0.0
- Individual freelancer or [For Hire] ad → 0.0

SCORE 4 DIMENSIONS (0.0-1.0):
1. relevance_score: 1.0=explicit AI/ML/automation RFP | 0.8=custom software/enterprise tech RFP | 0.6=general IT/software RFP | 0.3=tangential tech (security/network) | 0.0=non-tech or government RFP
2. budget_score: 1.0=$500K+ | 0.9=$200-500K | 0.8=$100-200K | 0.7=$50-100K | 0.6=$25-50K | 0.5=unknown but enterprise context | 0.3=$10-25K | 0.1=<$10K
3. urgency_score: 1.0=deadline this week/imminent | 0.8=deadline within 1 month | 0.6=proposals open now | 0.4=no deadline mentioned but active | 0.2=closed or archived
4. win_probability: 0.9+=small company RFP with perfect AI/ML fit | 0.8=mid-market RFP, strong fit | 0.7=competitive but good fit | 0.5=enterprise RFP, many vendors | 0.3=large enterprise, hard to win | 0.1=no fit

BUDGET ESTIMATION (ALWAYS fill estimated_budget_text, never null):
- Enterprise RFP ($500M+ company) → "$200K-$2M (enterprise procurement)"
- Mid-market RFP → "$50K-$500K (mid-market scope)"
- Startup/SMB RFP → "$25K-$150K (SMB scope)"
- AI/ML project RFP → "$75K-$500K (AI/ML engagement)"
- Automation/workflow RFP → "$50K-$300K (automation scope)"
- Unknown budget → "$50K-$300K (estimated private sector RFP)"

COMPANY EXTRACTION: Extract company name, contact name, website from title/snippet/URL. Never invent. Return null if not found.`;

const prompt = SYSTEM_PROMPT + `\n\nScore this private sector RFP. Return ONLY a single valid JSON object:\n{"relevance_score":0.0,"budget_score":0.0,"urgency_score":0.0,"win_probability":0.0,"summary":"3-5 sentence detailed summary: what the company is seeking, the scope of work, deadline if mentioned, and why ScaleBuild AI is the right fit","industry":"FinTech/HealthTech/SaaS/Manufacturing/eCommerce/Energy/Logistics/General","tags":["tag1","tag2"],"reasoning":"Full detailed AI reasoning: explain each score dimension — why this relevance, why this budget score, why this urgency, why this win probability. What specific signals make this a strong or weak lead. Recommended outreach angle and proposal approach.","estimated_budget_text":"$X-$Y (reason)","rfp_deadline":null,"rfp_scope":"brief scope summary","tech_stack":[],"company_name":null,"lead_founder_name":null,"lead_website":null}\n\nTitle: ${post.title}\nPlatform: ${post.source}\nDescription: ${(post.description||'').substring(0, 1200)}${post.budget_text ? '\nBudget: ' + post.budget_text : ''}`;

const body = {
  contents: [{ parts: [{ text: prompt }] }],
  generationConfig: { maxOutputTokens: 100000, temperature: 0.2, responseMimeType: 'application/json' }
};

let s = null;
try {
  const respRaw = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=' + apiKey,
    body
  });
  const resp = typeof respRaw === 'string' ? JSON.parse(respRaw) : respRaw;
  const raw = resp?.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const cleaned = raw.replace(/```json[\s\S]*?```|```/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) s = JSON.parse(match[0]);
} catch(e) {}

if (!s) s = {
  relevance_score:0.4, budget_score:0.5, urgency_score:0.3, win_probability:0.3,
  summary:'Parse error - using defaults', industry:'General', tags:[], reasoning:'Could not parse Gemini response',
  estimated_budget_text:'$50K-$300K (estimated private sector RFP)',
  rfp_deadline:null, rfp_scope:'Unknown scope',
  tech_stack:[], company_name:null, lead_founder_name:null, lead_website:null
};

const overall = Math.round(((s.relevance_score*0.35)+(s.budget_score*0.30)+(s.urgency_score*0.15)+(s.win_probability*0.20))*100)/100;
const alert_tier = overall>=0.85?'instant':overall>=0.70?'digest':overall>=0.30?'dashboard':'discard';

return { json: {
  source_id: post.source_id, title: post.title, description: post.description,
  source: post.source, source_url: post.source_url, posted_at: post.posted_at,
  author: post.author||'', subreddit: post.subreddit||post.source||'',
  upvotes: 0, num_comments: 0, flair_text: 'Private RFP',
  relevance_score: s.relevance_score, budget_score: s.budget_score,
  urgency_score: s.urgency_score, win_probability: s.win_probability,
  overall_score: overall, ai_summary: s.summary, industry: s.industry,
  ai_tags: s.tags||[], ai_reasoning: s.reasoning,
  estimated_budget_text: s.estimated_budget_text||'',
  budget_mentioned: post.budget_text || s.estimated_budget_text || '',
  tech_stack: s.tech_stack||[], company_name: s.company_name||null,
  lead_founder: s.lead_founder_name||null, lead_company: s.company_name||null,
  lead_website: s.lead_website||null, lead_contact: null,
  lead_score: Math.round(overall*10),
  alert_tier, discovered_at: new Date().toISOString(), status:'new',
  location: s.location||null, deadline_text: s.rfp_deadline||null,
  outreach_draft: '',
  hunter_name:'', hunter_email:'', hunter_title:'', hunter_company:'',
  hunter_all_emails:'', hunter_all_names:'', hunter_all_titles:''
}};

const hunterResp = $input.item.json;
const original = $('Check - Has Lead Info').item.json;
const data = hunterResp?.data || {};
const emails = data.emails || [];
const org = data.organization || original.lead_company || '';

if (emails.length === 0) {
  return [{ json: { ...original, hunter_name: '', hunter_email: '', hunter_title: '', hunter_company: org, hunter_all_emails: '', hunter_all_names: '', hunter_all_titles: '' } }];
}

// Pick best contact by seniority priority
const priority = ['ceo','founder','co-founder','cto','owner','president','vp','director'];
const best = emails.find(e => priority.some(t => (e.position||'').toLowerCase().includes(t))) || emails[0];

// Collect all emails, names, titles as comma-separated
const allEmails  = emails.map(e => e.value || '').filter(Boolean).join(', ');
const allNames   = emails.map(e => (e.first_name||e.last_name) ? `${e.first_name||''} ${e.last_name||''}`.trim() : '').filter(Boolean).join(', ');
const allTitles  = emails.map(e => e.position || '').filter(Boolean).join(', ');

return [{ json: {
  ...original,
  hunter_name:       best.first_name || best.last_name ? `${best.first_name||''} ${best.last_name||''}`.trim() : '',
  hunter_email:      best.value || '',
  hunter_title:      best.position || '',
  hunter_company:    org,
  hunter_all_emails: allEmails,
  hunter_all_names:  allNames,
  hunter_all_titles: allTitles
}}];

const seen = new Map();
for (const item of $input.all()) {
  const id = item.json.source_id;
  if (!id) continue;
  if (!seen.has(id)) {
    seen.set(id, item.json);
  } else {
    if (item.json.hunter_email && !seen.get(id).hunter_email) {
      seen.set(id, item.json);
    }
  }
}
return [...seen.values()]
  .sort((a, b) => (b.overall_score||0) - (a.overall_score||0))
  .map(json => ({ json }));
